  ('police-3218f787-moex-00147', 'police-3218f787', 'police-3218f787-moex-112-15a7b19c', 'sub-police-3218f787-01', NULL, 'single_choice', '依憲法及增修條文之規定，下列敘述何者錯誤？', '["總統對於院與院間之爭執，除憲法有規定者外，得召集有關各院院長會商解決", "總統解散立法院之命令，無須行政院院長之副署，不適用憲法第37條", "總統得經行政院會議之決議，發布緊急命令，不受憲法第43條之限制", "行政院院長不信任案後通過後，總統得不經諮詢立法院院長，直接宣告解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:10+00:00", "source_pdf_sha1": "4af07570f309", "answer_pdf_sha1": "fe1307bbe555", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "505", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "犯罪防治人員預防組"}'::jsonb, NULL),
